select coalesce(g.name, s.scientific_name) as name,
       case when s.scientific_name is null then 'missing_in_db' else 'missing_in_gen' end as problem
from gen g full outer join species s on s.scientific_name = g.name
where g.name is null or s.scientific_name is null;